import sys

class Solution:
    def solve(self, edges: list[list[int]], V: int) -> bool:
        graph = [[] for _ in range(V)]
        for u, v in edges:
            graph[u].append(v)

        visited = [0] * V

        def dfs(node: int) -> bool:
            if visited[node] == 1:  # currently in recursion stack
                return True
            if visited[node] == 2:  # already processed and no cycle found
                return False
            visited[node] = 1
            for neighbor in graph[node]:
                if dfs(neighbor):
                    return True
            visited[node] = 2
            return False

        for node in range(V):
            if visited[node] == 0 and dfs(node):
                return True
        return False

if __name__ == '__main__':
