#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    bool solve(vector<vector<int>>& edges, int V) {
        vector<vector<int>> graph(V);
        for (const auto& edge : edges) {
            graph[edge[0]].push_back(edge[1]);
        }

        vector<int> visited(V, 0);

        function<bool(int)> dfs = [&](int node) {
            if (visited[node] == 1) return true; // currently in recursion stack
            if (visited[node] == 2) return false; // already processed and no cycle found
            visited[node] = 1;
            for (int neighbor : graph[node]) {
                if (dfs(neighbor)) return true;
            }
            visited[node] = 2;
            return false;
        };

        for (int node = 0; node < V; ++node) {
            if (visited[node] == 0 && dfs(node)) return true;
        }
        return false;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int V, E;
    if (!(cin >> V >> E)) return 0;
    vector<vector<int>> edges(E, vector<int>(2));
    for (auto& edge : edges) {
        cin >> edge[0] >> edge[1];
    }
    Solution sol;
    bool ans = sol.solve(edges, V);
    cout << (ans ? "true" : "false") << "\n";
    return 0;
}
